						<div class="elementor-container elementor-column-gap-default">
					<div class="elementor-column elementor-col-50 elementor-top-column elementor-element elementor-element-69abae4" data-id="69abae4" data-element_type="column" data-e-type="column" data-settings=\'{"background_background":"classic"}\'>
			<div class="elementor-widget-wrap elementor-element-populated">
						<div class="elementor-element elementor-element-bc8e95e elementor-widget elementor-widget-spacer" data-id="bc8e95e" data-element_type="widget" data-e-type="widget" data-widget_type="spacer.default">
